var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈……哈……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이전 침식 사태의 대응으로 미약하게나마 별빛의 본질을 깨달으신 모양이군요.","JPN":"この前の侵食事態に対応しているうちに、少しですが星の光の本質に気が付かれているようですね。","ENG":"It seems the last Corruption disaster helped you grasp the essence of starlight, even if only slightly.","TWN":"看起來你在應對之前的侵蝕事件時，稍微領悟到了星光的本質。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 움직임이 부자연스럽습니다. 혹, 다른 누군가를 모방해내는 것 같군요.","JPN":"ですが、まだ動きが不自然です。まるで誰かのそれを真似ているかのように。","ENG":"But your movements are unnatural. It's as if you're imitating someone else.","TWN":"但你的動作顯得不自然。或許是在模仿其他人吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금 그걸 말이라고 하십니까?","JPN":"何ですか、それは！","ENG":"Is that really what you're going to say right now?","TWN":"你現在是在說什麼？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"읏!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃！?"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이게 무슨 짓입니까, 부인!","JPN":"どういうつもりですか、夫人！","ENG":"What are you doing, madam?!","TWN":"夫人，你這是在做什麼！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"마지막 한 사람이 남을 때까지 계속하여 싸운다 말하지 않았습니까?","JPN":"最後の一人になるまで戦い続ける、と言ったはずですよ？","ENG":"Didn't I say the battle continues until only one person remains?","TWN":"不是說要戰鬥到最後一個人嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"명색이 가문의 후계자가 제 가문 기사들의 추태를 보고 있을 수는 없는 법이지요.","JPN":"一族の後継者たる者、家門の騎士たちの醜態を見ているだけというわけにはいきませんから。","ENG":"As the heir of a noble house, I can't just sit back and watch my knights disgrace themselves.","TWN":"身為家族的繼承人，我不能坐視家族騎士們出醜。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"가호가 불안정해진 뒤로 몸이 뒤쳐질지 언정 판단이 뒤쳐지는 경우는 없었다.","JPN":"加護が不安定になってからというもの、体が遅れることはあっても判断が遅れることはなかった。","ENG":"Even after my blessing destabilized, my body lagged behind, not my judgment.","TWN":"即使在守護變得不穩定之後，身體可能會慢一拍，但判斷從未落後。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그런데 검의 궤적을 눈으로 쫓는 게 고작이라고?","JPN":"なのに、剣の軌跡を目で追うだけで精一杯だ。","ENG":"But all I can do is track her sword with my eyes?","TWN":"但是只能用眼睛追蹤劍的軌跡嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"청출어람이 되어버렸으나 알렌에게 검술을 가르친 건 저입니다.","JPN":"出藍の誉れとなってしまいましたが、アレンに剣術を教えたのは私なのです。","ENG":"He may have surpassed me, but I was the one who taught Allen how to wield a sword.","TWN":"青出於藍，但教艾倫劍術的是我。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그런 맥아리 없는 검술에 당하면 체면이 안 서지요.","JPN":"そのような気の弱い剣術にやられては、示しがつきません。","ENG":"Losing to such a limp excuse for swordsmanship would be embarrassing.","TWN":"被那種無力的劍術擊敗的話，顏面何存呢。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"매, 맥아리?","JPN":"気の弱い？","ENG":"L-limp?!","TWN":"什，什麼？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"내 검의 궤도를… 전부 앞질렀어?","JPN":"私の剣の軌道を……全部見抜いている？","ENG":"She read... every move of my blade?!","TWN":"我的劍軌……全部被你提前知道了？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무구를 통해 빚어낸 별빛이란 또한 기사의 내면을 비추는 심상과도 같습니다.","JPN":"武具を通じて作り出した星の光とは、騎士の内面が映し出されたもの。","ENG":"The starlight channeled through an Armament reflects the inner image of its wielder.","TWN":"通過武器打造出的星光，也如同騎士內心的意象一般。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"검술이 동작의 반복을 넘어 몸과 마음의 일치를 추구하는 것이 시작점이듯.","JPN":"剣術が、動作の繰り返しに留まらず、体と心の一体化を追求することから始めるように。","ENG":"Just as swordsmanship begins with unifying mind and body beyond mere repetition of movements.","TWN":"劍術的起點在於追求動作的重複超越身體與心靈的統一。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"적이 다루는 별빛을 읽어낼 수 있다면 그 움직임을 읽어내는 것은 쉬운 일이지요.","JPN":"敵が扱う星の光を読むことができれば、その動きを見抜くのはたやすいことです。","ENG":"Once you can read the starlight an opponent wields, anticipating their moves becomes simple.","TWN":"如果能解讀敵人操控的星光，那麼讀懂他們的動作就容易了。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자, 경께서도 따라해보세요.","JPN":"さあ、卿もどうぞご一緒に。","ENG":"Now then, why don't you give it a try?","TWN":"來，你也試著跟著做吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그런 게 가능했다면 이런 고생은 안 합니다!","JPN":"そのようなことができたなら、ここまで苦労はしません！","ENG":"If it were that easy, I wouldn't be struggling like this!","TWN":"如果那樣能行的話，我就不用這麼辛苦了！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음. 집중할 동기가 부족하다면 이렇게 하지요.","JPN":"そうですか。集中する動機が足りないのでしたら、こういたしましょう。","ENG":"Hmm. If you're lacking the motivation to focus, then allow me to fix that.","TWN":"嗯。如果缺乏集中注意力的動力，那就這樣做吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"만약 경께서 제 방어를 뚫어 내신다면, 하나의 <color=#ffd34c>질문</color>에 한해 어떤 것이든 답변하겠습니다.","JPN":"もし卿が私の防御を突破することができたなら、どんな<color=#ffd34c>質問</color>でも一つに限りお答えします。","ENG":"If you can break through my defense, I'll answer any one <color=#ffd34c>question</color> you ask.","TWN":"如果你能突破我的防禦，我將回答一個<color=#ffd34c>問題</color>，無論是什麼問題。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 제 말문이 막힐 정도로 날카로운 질문 말이죠.","JPN":"ええ。それはもう、私が言葉を失うほど鋭い質問でも。","ENG":"Yes. Even one so sharp it leaves me speechless.","TWN":"沒錯，令我難以啟齒的尖銳問題也可以。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"후회하실 겁니다.","JPN":"後悔しますよ。","ENG":"You'll regret that.","TWN":"你會後悔的。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 무서워라.","JPN":"あら、怖い。","ENG":"Oh my. How scary.","TWN":"哎呀，真可怕呀。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"호승심 넘치게 말했으나 상대의 공격은 눈으로 쫓는 게 고작이다.","JPN":"自信満々に言いはしたが、相手の攻撃を目で追うのが精一杯。","ENG":"She boasted with confidence, but all she could manage was to follow her opponent's attacks with her eyes.","TWN":"雖然說得很有鬥志，但只能用眼睛追蹤對方的攻擊。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"하지만, 자신보다 강한 상대와 싸운 기억은 숱하게 있다.","JPN":"だが、自分より強い相手と戦った経験なら、いくらでもある。","ENG":"Still, she'd faced stronger opponents many times before.","TWN":"不過，與比自己強的對手戰鬥的記憶已經有很多了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"BATTLE_NORMAL_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그렇다면…!!","JPN":"だとしたら……！！","ENG":"In that case...!!","TWN":"這樣的話…！！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"쓰러진 기사들의 검을 던져 소모전을 할 생각이로군요.","JPN":"倒れた騎士たちの剣を投げ、消耗戦に突入するおつもりなのですね。","ENG":"Using the fallen knights' swords to wear me down, is it?","TWN":"看來你打算用倒下騎士的劍進行消耗戰呢。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무작정 달려들지 않는 것은 현명합니다만, 이래서는 경께서도 제게 접근하지 못합니다.","JPN":"むやみにかかってこないことは賢明な判断ですが、これでは卿も私に近づくことはできません。","ENG":"It's wise not to rush in recklessly, but you still won't be able to reach me this way.","TWN":"不貿然衝上去是明智的，但這樣的話，你也無法接近我。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머.","JPN":"あら。","ENG":"Oh?","TWN":"哎呀。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"치잇!","JPN":"ちっ！","ENG":"Tch!","TWN":"嘖！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"훌륭합니다. 직전 공격은 로브 안에 검을 숨기기 위한 공작이었군요.","JPN":"素晴らしい。直前の攻撃はローブの中に剣を隠すための工作だったのですね。","ENG":"Well done. That last strike was a decoy to conceal your sword inside your robe, wasn't it?","TWN":"太棒了。剛才的攻擊是為了在斗篷裡藏劍的伎倆啊。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허나 주변의 검을 모두 소진하였으니, 접근하리라는 건 뻔해요.","JPN":"ですが、周りの剣をすべて使い果たしたら、次は接近戦に持ち込もうという考えがみえみえです。","ENG":"But now that you've exhausted the surrounding weapons, a direct charge is all that's left.","TWN":"不過周圍的劍已經耗盡，接近是顯而易見的。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 예상대로입니다.","JPN":"いいえ。予想どおりです。","ENG":"No. It's exactly as planned.","TWN":"不，果然在我意料之中。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인께서라면 분명 제 공격을 받아주실 거라 생각했으니까요.","JPN":"夫人なら私の攻撃を受け止めてくれると思いましたから。","ENG":"I knew you'd accept my strike head-on.","TWN":"因為我覺得夫人一定會接下我的攻擊。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"맞부딪힌 검 위에… 로브를 씌웠어?","JPN":"合わさった剣の上に……ローブを？","ENG":"You wrapped your robe... around our locked blades?","TWN":"在交鋒的劍上……披上了斗篷？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"분명 말씀하셨습니다. 연무장에서 피를 보는 일은 없을 테니 안심하라고.","JPN":"おっしゃいましたよね。訓練場で血を見ることはないはずだから安心しろと。","ENG":"You said there would be no bloodshed in the training hall, and I took you at your word.","TWN":"你明確說過。在演武場不會見血，請放心。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"로브를 제 손으로 붙잡고 있으니… 이걸 베어내려는 순간 제 손은 날아가겠죠.","JPN":"ローブを掴む私の手……ローブを斬ろうとした瞬間、私の手も切り落とされるでしょう。","ENG":"Since I'm holding the robe in place, if you try to cut through it, you'll take off my hand too.","TWN":"我親手抓住了斗篷……在試圖砍斷它的瞬間，我的手也會飛出去吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"허면 검을 내려놓은 뒤 거리를 벌리면 그만입니다.","JPN":"それなら、剣を放して距離を置けば済むことです。","ENG":"Then I could simply drop the sword and back away.","TWN":"那麼只要放下劍，拉開距離就行了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무기라면 쓰러진 기사들의 것이 있으니…….","JPN":"武器なら倒れた騎士たちのものが……","ENG":"There are still plenty of weapons from the others lying around, after all...","TWN":"如果是武器的話，可以用那些倒下騎士的……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……이런.","JPN":"……あら。","ENG":"...Oh dear.","TWN":"……這樣啊。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당했네요.","JPN":"やられましたね。","ENG":"You got me.","TWN":"……上當了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"승부에서 이긴 건 경인데, 무엇이 그리도 불만족스러우십니까?","JPN":"勝負に勝ったのは卿ですのに、何がご不満なのでしょうか？","ENG":"You've won the match, yet you still look dissatisfied.","TWN":"勝負已定，你為何仍感到不滿？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"놀리지 마시죠, 부인.","JPN":"からかわないでください、夫人。","ENG":"Don't mock me.","TWN":"別取笑我，夫人。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인께서 날리신 주먹에 도리에 제가 쓰러지고 말았습니다.","JPN":"夫人の拳に、私が倒れてしまったではないですか。","ENG":"You're the one who knocked me flat with a punch.","TWN":"夫人揮出的拳頭讓我措手不及，最終倒下了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 제 명치를 노리셨으니 제 입장에서는 정당방위였습니다.","JPN":"卿が私のみぞおちを狙いましたので、正当防衛です。","ENG":"You aimed for my solar plexus. I call that self-defense.","TWN":"你瞄準了我的心口，所以我只是正當防衛而已。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"연무장에서 사사로운 감정을 담으면 안 되지요, 에스텔.","JPN":"訓練場に私情を持ち込んではいけませんよ、エステル。","ENG":"You shouldn't bring personal feelings into the training hall, Esther.","TWN":"在演武場上不能夾雜私人情感，艾斯特。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어쨌든 내기는 제 승리입니다.","JPN":"とにかく、賭けは私の勝ちです。","ENG":"Regardless, I won the wager.","TWN":"無論如何，賭局是我贏了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제대로 된 유효타는 없었으나, 방어를 뚫어내는 것 자체에는 성공했으니까요.","JPN":"決め手となる攻撃はできなかったものの、防御を突破すること自体には成功しましたから。","ENG":"I may not have landed a clean hit, but I did break through your guard.","TWN":"雖然沒有造成有效打擊，但至少成功突破了防禦。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"물론입니다. 경께서 궁금하신 거라면 무엇이든 대답해드리지요.","JPN":"もちろんです。卿の疑問に何でもお答えいたしましょう。","ENG":"Of course. I will answer any question you ask.","TWN":"當然。如果你有任何疑問，我都會回答。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 제 말문이 막힐 정도의 날카로운 질문에 한해서요.","JPN":"ええ。言葉を失うほどに鋭い質問に限ってね。","ENG":"So long as it's sharp enough to leave me speechless.","TWN":"是的。僅限令我難以啟齒的尖銳問題。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"잠깐. 그건 약속과는 다르지 않습니까?","JPN":"待ってください。それは約束とは違うでしょう？","ENG":"Wait, that wasn't the deal. You're changing the terms.","TWN":"等一下。這和我們的約定不一樣吧？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무슨 말씀이십니까? 저는 분명 그런 질문에 답하겠다 명시해드렸을 텐데요.","JPN":"何をおっしゃるのでしょうか。私は確かにそのような質問にお答えいたしますと明示しました。","ENG":"Whatever do you mean? I clearly said I'd answer a truly sharp question.","TWN":"你說什麼？我明明已經明確表示會回答那樣的問題了啊。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"승부에 매몰되어도 사람 말은 똑바로 들어야지요. 누가 들으면 제가 거짓말이라도 한 줄 알겠습니다.","JPN":"勝負に没頭しても、人の話は正確に聞かないといけません。私が嘘をついたと思われてもいけませんし。","ENG":"Even if you're caught up in the match, you should still listen properly. Otherwise, someone might think I lied.","TWN":"即使沉迷於勝負，也要好好聽人說話。要是有人聽了，還以為我在撒謊呢。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리 섭섭하게 쳐다보지 마시지요. 이는 연무장에서 주먹다짐을 한 벌이기도 합니다.","JPN":"そう恨めしそうに見ないでください。これは訓練場で殴り合いをした罰でもあるのです。","ENG":"Oh, don't look at me like that. Consider this a little penalty for throwing punches in the training hall.","TWN":"別用那種失落的眼神看著我。這也是在演武場上打架的懲罰。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제시해 주신 계책은 퍽 훌륭했으나 자신을 내거는 것을 수단에 포함해서야…….","JPN":"見せていただいた策はとても素晴らしかったのですが、自分の身を犠牲にすることを手段に入れるのは……","ENG":"Your tactic was clever, I'll give you that. But when you use yourself as bait...","TWN":"你提出的計策非常出色，但將自己作為手段的一部分……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기사보다는 죽음을 직시한 반송장이나 다름없겠지요.","JPN":"騎士というよりは死を覚悟した者のすることです。","ENG":"You're no knight. You're a walking corpse with a death wish.","TWN":"與其說是騎士，不如說是直接迎向死亡的行屍走肉吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……됐습니다. 질문은 중요한 순간으로 미뤄두죠.","JPN":"……もういいです。質問はここぞという時のために取っておくことにします。","ENG":"...Fine. I'll save my question for later.","TWN":"……好了。問題留到關鍵時刻再問吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 괜찮으신가요?","JPN":"あら。よろしいの？","ENG":"Oh? Are you sure?","TWN":"哎呀。你沒事吧？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당장의 기회를 쓰지 못하도록 의도적으로 상황을 피하는 것은 부인이 아니십니까.","JPN":"この場で質問ができないように、意図的に状況を避けているのは夫人の方ではないですか。","ENG":"You're the one dodging the moment, not me.","TWN":"不是你刻意讓我無法發問的嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 의도가 무엇이든, 부인께서 저를 이용하신다면 저 또한 그것을 이용할 뿐입니다.","JPN":"その意図はわかりませんが、夫人が私を利用するというなら私もまたそれを利用するだけです。","ENG":"Whatever your intentions, if you plan to use me, I'll do the same to you.","TWN":"無論你的意圖是什麼，如果夫人利用我，我也只會利用回去而已。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"적어도 부인께 협력하면 무언가 알 수 있으리란 것은 자명하니까요.","JPN":"少なくとも夫人に協力すれば何かがわかるということは明白ですから。","ENG":"At the very least, cooperating with you is bound to get me some answers.","TWN":"至少與夫人合作的話，肯定能學到一些東西。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"좋네요. 상호협력관계라는 거군요.","JPN":"良いでしょう。相互協力関係というものですね。","ENG":"I like that. A mutual partnership, then.","TWN":"很好，看來我們是互助關係了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 제게 협력해 주신다니 앞으로의 원정 또한 든든하기 그지없습니다.","JPN":"卿が私に協力してくださるのなら、これからの遠征も心強いです。","ENG":"With your support, this expedition is looking more promising than ever.","TWN":"有你的協助，未來的遠征將更加穩妥無虞。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"방금, 원정이라고 하셨습니까?","JPN":"今、遠征とおっしゃいましたか？","ENG":"Did you just say expedition?","TWN":"剛才，你說遠征？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 백작가. 더 나아가 제국의 숙원을 이루기 위한 중요한 원정입니다.","JPN":"ええ。伯爵家、さらには帝国の宿願を叶える、重要な遠征です。","ENG":"Yes. A crucial mission to fulfill the long-cherished wish of my house and of the Empire itself.","TWN":"是的。伯爵家，要往前更邁進一步，這是為了實現帝國夙願的重要遠征。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"내일이 출전이니 경께서도 떠날 채비를 마쳐 두시지요.","JPN":"明日が出征日ですので、卿も旅のご用意を。","ENG":"We leave tomorrow. Make sure you're ready.","TWN":"明天就要出征了，你也請做好出發的準備吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"촌장님. 서쪽 방향의 숲에서도 에스테로사가 없었습니다.","JPN":"村長。西側の森にもエステロサは居ませんでした。","ENG":"Chief, we searched the woods to the west, but there's still no sign of Esterosa.","TWN":"村長。西邊方向的森林裡也沒有發現艾斯特洛索。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"침식사태가 끝났는데도 돌아오지 않는 걸 보면, 어쩌면…….","JPN":"侵食事態が終わっても戻らないのは、もしかしたら……","ENG":"The Corruption disaster is over, yet she hasn't returned... I fear the worst.","TWN":"侵蝕事態已經結束了，但還是沒有回來，或許……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그런 소리 마시죠. 재능이 없다고 손가락질 받음에도 굳은 심지로 기사가 된 아이입니다.","JPN":"止しましょう。才能がないとばかにされても、強い意志で騎士になった子です。","ENG":"Don't say that. That girl became a knight through sheer determination, even when everyone called her talentless.","TWN":"別說那種話。即使被指責沒有才能，她也憑藉堅定的意志成為了騎士。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"그런 아이가 이렇게 쉽게 죽을 리가 없어요.","JPN":"そんな子がこうも簡単に死ぬわけがありません。","ENG":"She's not the kind to die so easily.","TWN":"那樣的孩子不可能那麼容易死。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"하지만… 저희 만으로는 침식지대를 찾는데 한계가 있어요.","JPN":"でも……私たちだけで侵食地帯を探すのには限界があります。","ENG":"Still... we're struggling to search the Corrupted Area on our own.","TWN":"但是……僅靠我們自己尋找侵蝕地帶是有極限的。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"샤레이드 쪽에 사람을 보냈지만, 거리가 멀어 언제 도움을 받을 수 있을지도 모르고요.","JPN":"シャレードの方に人を行かせましたが、距離があるのでいつ支援に来てもらえるか……","ENG":"We sent someone to Charade, but it's far. We don't know when help will arrive.","TWN":"雖然派人去了查雷德，但距離太遠，不知道什麼時候才能得到幫助。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"호오. 괜찮다면 그 이야기를 자세히 듣고 싶군.","JPN":"ほう。よければその話、詳しく聞かせてくれないか。","ENG":"Hmm. I'd like to hear more about that, if you don't mind.","TWN":"喔呵，方便的話，可以把詳情說給我聽嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"사, 사람? 그쪽 방면은 침식지대일 텐데, 어떻게?","JPN":"ひ、人だと？　そっちは侵食地帯なのに、どうやって？","ENG":"W-who's there?! That direction's a Corrupted Area! How did you–?!","TWN":"人，人類？那邊應該是侵蝕地帶，怎麼會？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"짖어대는 미물들이라면 처리했다. 주제도 모르는 것들이 불쾌히 덤벼 들더군.","JPN":"うるさい虫けらどもなら処理した。身の程も知らず、不愉快にも飛びかかって来てな。","ENG":"The yapping beasts are taken care of. Disgusting things didn't know their place.","TWN":"那些吠叫的小蟲子已經處理掉了。不知天高地厚的東西居然敢冒犯我。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"처리하다니… 설마 카운터이신 겁니까?","JPN":"処理したって……あなた、カウンターですか？","ENG":"Taken care of...? Wait, are you a Counter?","TWN":"解決掉了……難道你是制裁者嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"그, 그렇다면 부탁드립니다! 실은 마을에서 사람 한 명이 사라졌어요!","JPN":"そ、それならお願いがあります！　実は、1人、村からいなくなったのです！","ENG":"Then please, I beg you! Someone from our village has gone missing!","TWN":"那，那就拜託你了！其實村子裡有一個人失蹤了！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"이름은 에스테로사인데, 몸에 로브를 걸친 여자아이입니다!","JPN":"名前はエステロサといって、ローブを被っている女の子です！","ENG":"Her name is Esterosa. She's a girl in a robe!","TWN":"名字是艾斯特洛索，身上披著披風的女孩！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"부디 그 아이를 찾아주십시오…!","JPN":"どうかあの子を探してください……！","ENG":"Please find her for us...!","TWN":"請幫我找到那個孩子……！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"에스테로사… 그래, 에스테로사라.","JPN":"エステロサ……そうか、エステロサか。","ENG":"Esterosa... Yes, Esterosa...","TWN":"艾斯特洛索…對，艾斯特洛索。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_4"},{"id":"L25_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"잘 됐군.","JPN":"ちょうどよかった。","ENG":"Perfect.","TWN":"看來不錯。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_5"},{"id":"L26_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"마침, 그녀석에게 용무가 있던 참이었다.","JPN":"そいつに用があったのだ。","ENG":"I've been meaning to have a word with her.","TWN":"正好，我有事要找那傢伙。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_6"}]`);export{e as default};